const row = $('Fetch competitor_backlinks data').item.json;

const dr = row.domain_rating;

let authority_score = 0;

if (dr >= 80) {
  authority_score = 90;
}
else if (dr >= 60) {
  authority_score = 75;
}
else if (dr >= 40) {
  authority_score = 60;
}
else if (dr >= 20) {
  authority_score = 40;
}
else {
  authority_score = 20;
}

let link_type = $json.nofollow
  ? "NOFOLLOW"
  : "DOFOLLOW";

let opportunity_score = authority_score;

if (!($json.nofollow)) {
  opportunity_score += 10;
}

opportunity_score = Math.min(opportunity_score, 100);

return {
  ...$('Fetch competitor_backlinks data').item.json,

  authority_score,

  opportunity_score,

  link_type
};

const backlinks = $input.all().map((item, index) => ([
    index,
    item.json.domain_rating,
    item.json.anchor_text
]));

const uuidMap = $input.all().map((item, index) => ({
    index,
    id: item.json.competitor_backlinks_id
}));

return [{
    json: {
        backlinks,
        uuidMap
    }
}];

const llmResults = $json.output.results;

const uuidMap = $('Prepare For LLM').first().json.uuidMap;

return llmResults.map(row => {

  const index = row[0];

  const mapping = uuidMap.find(
    x => x.index === index
  );

  return {
    json: {
      competitor_backlinks_id: mapping?.id || null,
      relevance_score: row[1],
      spam_score: row[2]
    }
  };

});

return $input.all().map(item => {

    const relevance =
        item.json.relevance_score;

    const spam =
        item.json.spam_score;

    let recommendation;

    if(relevance >= 80 && spam <= 20)
        recommendation = "KEEP";

    else if(relevance >= 60 && spam <= 40)
        recommendation = "KEEP_MONITOR";

    else if(relevance >= 40 && spam <= 60)
        recommendation = "MONITOR";

    else if(spam > 60 && spam <= 80)
        recommendation = "REVIEW";

    else
        recommendation = "DISAVOW";

    return {
        json:{
            ...item.json,
            recommendation
        }
    };
});

return [{
  json: {
    success: false,
    status: "LLM_FAILED",
    error: $json.error?.message || "Unknown LLM Error"
  }
}];

return [{
  json: {
    success: true,
    status: "SUCCESS",
    processed: $input.all().length
  }
}];

return [{
  json:{
    success:false,
    error:"No backlinks found"
  }
}];
